const fs = require('fs');
const path = require('path');

/**
 * Reads a log file from a designated logs directory based on user-provided filename.
 * Implements path traversal prevention through canonicalization and validation.
 * 
 * @param {string} userFilename - The filename provided by the user
 * @param {string} [baseDir] - Optional base directory for log files (defaults to ./logs)
 * @returns {Promise<string>} The contents of the log file
 * @throws {Error} If the filename is invalid, the path escapes the base directory, or the file cannot be read
 */
async function readLogFile(userFilename, baseDir) {
    // Default base directory for log files
    const resolvedBaseDir = path.resolve(baseDir || path.join(__dirname, 'logs'));

    // Input validation: reject null, undefined, empty, or non-string input
    if (!userFilename || typeof userFilename !== 'string') {
        throw new Error('Invalid filename: filename must be a non-empty string.');
    }

    // Trim whitespace
    const trimmedFilename = userFilename.trim();

    if (trimmedFilename.length === 0) {
        throw new Error('Invalid filename: filename must not be empty or whitespace.');
    }

    // Reject absolute paths outright
    if (path.isAbsolute(trimmedFilename)) {
        throw new Error('Invalid filename: absolute paths are not allowed.');
    }

    // Reject any path traversal segments (.. or .) as directory components
    // This is an additional defense layer, not the sole check
    const pathSegments = trimmedFilename.split(/[/\\]/);
    for (const segment of pathSegments) {
        if (segment === '..' || segment === '.') {
            throw new Error('Invalid filename: path traversal sequences are not allowed.');
        }
    }

    // Reject null bytes which can be used to truncate paths in some contexts
    if (trimmedFilename.includes('\0')) {
        throw new Error('Invalid filename: null bytes are not allowed.');
    }

    // Allowlist: only permit common log file extensions
    const allowedExtensions = ['.log', '.txt', '.json', '.csv'];
    const fileExtension = path.extname(trimmedFilename).toLowerCase();
    if (!allowedExtensions.includes(fileExtension)) {
        throw new Error(
            `Invalid filename: file extension "${fileExtension}" is not allowed. ` +
            `Allowed extensions: ${allowedExtensions.join(', ')}`
        );
    }

    // Allowlist: reject filenames with suspicious characters
    // Only allow alphanumeric, hyphens, underscores, dots, and path separators
    const safeFilenamePattern = /^[a-zA-Z0-9_\-./\\]+$/;
    if (!safeFilenamePattern.test(trimmedFilename)) {
        throw new Error('Invalid filename: contains disallowed characters.');
    }

    // Canonicalize: resolve the full path
    const fullPath = path.resolve(resolvedBaseDir, trimmedFilename);

    // Critical boundary check: ensure the resolved path starts with the base directory
    const canonicalBaseDir = path.resolve(resolvedBaseDir) + path.sep;
    if (!fullPath.startsWith(canonicalBaseDir)) {
        throw new Error('Invalid filename: access denied. The resolved path is outside the allowed directory.');
    }

    // Verify the file exists and is a regular file (not a symlink to outside, directory, etc.)
    try {
        // Use lstat to detect symlinks without following them
        const lstat = await fs.promises.lstat(fullPath);

        if (lstat.isSymbolicLink()) {
            // If it's a symlink, resolve it and verify the target is still within bounds
            const realPath = await fs.promises.realpath(fullPath);
            if (!realPath.startsWith(canonicalBaseDir)) {
                throw new Error('Invalid filename: access denied. Symlink target is outside the allowed directory.');
            }
        }

        if (!lstat.isFile() && !lstat.isSymbolicLink()) {
            throw new Error('Invalid filename: the path does not point to a regular file.');
        }
    } catch (err) {
        if (err.code === 'ENOENT') {
            throw new Error(`File not found: "${trimmedFilename}" does not exist in the logs directory.`);
        }
        // Re-throw our own validation errors
        if (err.message.startsWith('Invalid filename')) {
            throw err;
        }
        throw new Error(`Error accessing file: ${err.message}`);
    }

    // Read and return the file contents
    try {
        const contents = await fs.promises.readFile(fullPath, 'utf-8');
        return contents;
    } catch (err) {
        if (err.code === 'EACCES') {
            throw new Error('Permission denied: unable to read the log file.');
        }
        throw new Error(`Error reading file: ${err.message}`);
    }
}

